1	type Item = { type: string; material: string; enchantment: number; cursed: boolean };
2	type Step = { op: string; items: Item[] };
3	type Result = { premium: number };
4	type ScenarioInput = { customer: { yearsWithMHPCO: number }; steps: Step[] };
5	type ScenarioOutput = { results: Result[] };
6	
7	const COMPONENT_BASE_PREMIUM = 25;
8	const COMPONENT_BUNDLE_PREMIUM = 60;
9	const COMPONENT_BUNDLE_SIZE = 3;
10	const COMPONENT_TYPES = ["rune", "moonstone"];
11	
12	const BASE_PREMIUMS: Record<string, number> = {
13	  sword: 100,
14	  amulet: 60,
15	  staff: 80,
16	  potion: 40,
17	  rune: COMPONENT_BASE_PREMIUM,
18	  moonstone: COMPONENT_BASE_PREMIUM,
19	};
20	
21	const FIRST_INSURANCE_SURCHARGE_PERCENT = 10;
22	const CURSED_SURCHARGE_PERCENT = 50;
23	const HIGH_ENCHANTMENT_SURCHARGE_PERCENT = 30;
24	const HIGH_ENCHANTMENT_THRESHOLD = 5;
25	const LOYALTY_DISCOUNT_PERCENT = 20;
26	const LOYALTY_THRESHOLD_YEARS = 2;
27	const REPEAT_CONTRACT_DISCOUNT_PERCENT = 15;
28	const PROCESSING_FEE = 5;
29	
30	const addSurchargePercent = (amount: number, percent: number): number =>
31	  (amount * (100 + percent)) / 100;
32	
33	const applyDiscountPercent = (amount: number, percent: number): number =>
34	  (amount * (100 - percent)) / 100;
35	
36	const addSurchargeIf = (amount: number, condition: boolean, percent: number): number =>
37	  condition ? addSurchargePercent(amount, percent) : amount;
38	
39	const applyDiscountIf = (amount: number, condition: boolean, percent: number): number =>
40	  condition ? applyDiscountPercent(amount, percent) : amount;
41	
42	const itemPremium = (item: Item): number => {
43	  const base = BASE_PREMIUMS[item.type];
44	  const withCursed = addSurchargeIf(base, item.cursed, CURSED_SURCHARGE_PERCENT);
45	  return addSurchargeIf(
46	    withCursed,
47	    item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD,
48	    HIGH_ENCHANTMENT_SURCHARGE_PERCENT,
49	  );
50	};
51	
52	const sumItemPremiums = (items: Item[]): number =>
53	  items.reduce((sum, item) => sum + itemPremium(item), 0);
54	
55	const componentBundleDiscount = (items: Item[]): number => {
56	  let discount = 0;
57	  for (const componentType of COMPONENT_TYPES) {
58	    const count = items.filter((item) => item.type === componentType).length;
59	    const bundles = Math.floor(count / COMPONENT_BUNDLE_SIZE);
60	    discount += bundles * (COMPONENT_BUNDLE_SIZE * COMPONENT_BASE_PREMIUM - COMPONENT_BUNDLE_PREMIUM);
61	  }
62	  return discount;
63	};
64	
65	const quotePremium = (items: Item[], yearsWithMHPCO: number, isFirstQuote: boolean): number => {
66	  const itemsTotal = sumItemPremiums(items) - componentBundleDiscount(items);
67	  const withContractAdjustment = isFirstQuote
68	    ? addSurchargePercent(itemsTotal, FIRST_INSURANCE_SURCHARGE_PERCENT)
69	    : applyDiscountPercent(itemsTotal, REPEAT_CONTRACT_DISCOUNT_PERCENT);
70	  const withLoyalty = applyDiscountIf(
71	    withContractAdjustment,
72	    yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS,
73	    LOYALTY_DISCOUNT_PERCENT,
74	  );
75	  return withLoyalty + PROCESSING_FEE;
76	};
77	
78	export const runScenario = (input: ScenarioInput): ScenarioOutput => ({
79	  results: input.steps.map((step, index) => ({
80	    premium: quotePremium(step.items, input.customer.yearsWithMHPCO, index === 0),
81	  })),
82	});
