1	import { describe, it, expect } from "vitest";
2	import { runScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  it("returns no results for an empty steps array", () => {
6	    const result = runScenario({ customer: { yearsWithMHPCO: 0 }, steps: [] });
7	    expect(result).toEqual({ results: [] });
8	  });
9	  it("quotes a single sword for a new customer (base + first-insurance surcharge + processing fee)", () => {
10	    const result = runScenario({
11	      customer: { yearsWithMHPCO: 0 },
12	      steps: [
13	        {
14	          op: "quote",
15	          items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }],
16	        },
17	      ],
18	    });
19	    expect(result).toEqual({ results: [{ premium: 115 }] });
20	  });
21	  it("quotes each main item type with its own base premium", () => {
22	    const result = runScenario({
23	      customer: { yearsWithMHPCO: 0 },
24	      steps: [
25	        {
26	          op: "quote",
27	          items: [
28	            { type: "sword", material: "steel", enchantment: 0, cursed: false },
29	            { type: "amulet", material: "silver", enchantment: 0, cursed: false },
30	            { type: "staff", material: "oak", enchantment: 0, cursed: false },
31	            { type: "potion", material: "glass", enchantment: 0, cursed: false },
32	          ],
33	        },
34	      ],
35	    });
36	    // (100+60+80+40) * 1.10 + 5 = 308 + 5 = 313
37	    expect(result).toEqual({ results: [{ premium: 313 }] });
38	  });
39	  it("applies the 50% cursed surcharge", () => {
40	    const result = runScenario({
41	      customer: { yearsWithMHPCO: 0 },
42	      steps: [
43	        {
44	          op: "quote",
45	          items: [{ type: "sword", material: "steel", enchantment: 0, cursed: true }],
46	        },
47	      ],
48	    });
49	    // 100 * 1.5 = 150; * 1.10 = 165; + 5 = 170
50	    expect(result).toEqual({ results: [{ premium: 170 }] });
51	  });
52	  it("applies the 30% high-enchantment surcharge (level >= 5)", () => {
53	    const result = runScenario({
54	      customer: { yearsWithMHPCO: 0 },
55	      steps: [
56	        {
57	          op: "quote",
58	          items: [{ type: "sword", material: "steel", enchantment: 5, cursed: false }],
59	        },
60	      ],
61	    });
62	    // 100 * 1.30 = 130; * 1.10 = 143; + 5 = 148
63	    expect(result).toEqual({ results: [{ premium: 148 }] });
64	  });
65	  it("applies the 20% loyalty discount for customers with >= 2 years", () => {
66	    const result = runScenario({
67	      customer: { yearsWithMHPCO: 2 },
68	      steps: [
69	        {
70	          op: "quote",
71	          items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }],
72	        },
73	      ],
74	    });
75	    // 100 * 1.10 = 110; * 0.80 = 88; + 5 = 93
76	    expect(result).toEqual({ results: [{ premium: 93 }] });
77	  });
78	  it("applies the 15% repeat-contract discount on quotes after the first", () => {
79	    const result = runScenario({
80	      customer: { yearsWithMHPCO: 0 },
81	      steps: [
82	        {
83	          op: "quote",
84	          items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }],
85	        },
86	        {
87	          op: "quote",
88	          items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }],
89	        },
90	      ],
91	    });
92	    // Quote 1 (first insurance): 100 * 1.10 + 5 = 115
93	    // Quote 2 (repeat -15%):     100 * 0.85 + 5 = 90
94	    expect(result).toEqual({ results: [{ premium: 115 }, { premium: 90 }] });
95	  });
96	  it("prices components below the bundle threshold at 25 G each", () => {
97	    const result = runScenario({
98	      customer: { yearsWithMHPCO: 0 },
99	      steps: [
100	        {
101	          op: "quote",
102	          items: [
103	            { type: "rune", material: "stone", enchantment: 0, cursed: false },
104	            { type: "rune", material: "stone", enchantment: 0, cursed: false },
105	          ],
106	        },
107	      ],
108	    });
109	    // 2 runes (no bundle): 25 + 25 = 50; * 1.10 = 55; + 5 = 60
110	    expect(result).toEqual({ results: [{ premium: 60 }] });
111	  });
112	  it("prices a bundle of 3 alike components at 60 G base premium", () => {
113	    const result = runScenario({
114	      customer: { yearsWithMHPCO: 0 },
115	      steps: [
116	        {
117	          op: "quote",
118	          items: [
119	            { type: "rune", material: "stone", enchantment: 0, cursed: false },
120	            { type: "rune", material: "stone", enchantment: 0, cursed: false },
121	            { type: "rune", material: "stone", enchantment: 0, cursed: false },
122	          ],
123	        },
124	      ],
125	    });
126	    // bundle of 3 runes: 60; * 1.10 = 66; + 5 = 71
127	    expect(result).toEqual({ results: [{ premium: 71 }] });
128	  });
129	  it.todo("rounds the final premium up (in MHPCO's favor)");
130	  it.todo("returns a claim payout of 0 when damage is below the 100 G deductible");
131	  it.todo("reimburses dragon-material damage in full, minus the deductible");
132	  it.todo("reimburses high-enchantment (level >= 8) damage at 50%, minus the deductible");
133	  it.todo("returns 0 payout when neither dragon material nor high enchantment applies");
134	});
